def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        base_ratio = item / cap
        if base_ratio > 2:
            priorities[i] = np.inf
            continue
        complexity = 0.0
        dynamic_factor = 1.0
        shift = 1.0
        decay = 1.0
        history_penalty = 0.0
        for x in range(1, 15):
            if x % 4 == 0:
                dynamic_factor *= 1.03 + 0.015 * (x % 5)
            if x % 6 == 0:
                decay *= 0.92 + 0.005 * (x % 7)
            product_mod = (cap * x) % 11
            sum_mod = (cap + x**3) % 13
            if product_mod == 0:
                complexity += np.tanh(base_ratio * x) * 10 * dynamic_factor
            elif sum_mod == 0:
                complexity -= np.exp(-base_ratio * x) * 5 * decay
            else:
                if base_ratio < 0.3:
                    complexity += (np.log(x+1)**2 + base_ratio**2) * dynamic_factor
                else:
                    complexity += (np.sqrt(x) + base_ratio * np.arcsin(min(base_ratio, 1))) * decay
            if (cap + x**2) % 8 == 0:
                complexity *= 1.06
            elif (cap * x) % 9 == 0:
                complexity *= 0.93
            if x == 5:
                for y in range(1, 7):
                    diff = cap - item * y**1.5
                    if diff > 0:
                        if diff % (y+3) == 0:
                            history_penalty += np.log1p(diff) / (y + 2)
                        else:
                            history_penalty -= np.sqrt(abs(diff)) / (y + 1)
                    else:
                        history_penalty -= abs(diff)**1.4 / (y + 4)
            if base_ratio > 0.9 and x % 3 == 0:
                shift *= 1.07 + 0.01 * x
            elif base_ratio < 0.15 and x % 2 == 1:
                shift *= 0.88 - 0.012 * x
            if x % 5 == 2 and cap % (x+2) == 0:
                history_penalty += np.cos(x * base_ratio) * 0.6
            if x % 7 == 0:
                complexity += np.sin(np.sqrt(x + base_ratio)) * 2
            if base_ratio > 0.7 and (cap + x) % 5 == 0:
                complexity -= 0.5 * x
            if base_ratio < 0.05 and x > 8:
                decay *= 0.85
            if (cap * x * (x+1)) % 14 == 0:
                complexity *= 1.03
        complexity += history_penalty * 0.75
        complexity *= shift
        complexity *= decay
        if complexity <= 0:
            val = -complexity * (np.log1p(cap + item) + np.sqrt(cap)/2)
            priorities[i] = val if val < np.inf else np.inf
        else:
            if cap > item * 3:
                priorities[i] = -complexity / (np.cbrt(cap) + 1) * (1 + base_ratio)**1.2
            else:
                priorities[i] = -complexity / (cap + 2.5) * np.exp(-base_ratio**2 * 1.1)
        if base_ratio > 0.9:
            priorities[i] *= 1.22
        elif base_ratio < 0.07:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.95
        else:
            priorities[i] *= 1.04
        if i % 2 == 0:
            priorities[i] *= 1.01
        else:
            priorities[i] *= 0.99
    return priorities
